-- Case 008: COPY INTO location unload with partitioning and complex SELECT
COPY INTO @MART.EXPORT_STAGE/customer_score_daily/ FROM(WITH latest AS(SELECT customer_id,score_date,model_version,score,percentile,OBJECT_CONSTRUCT_KEEP_NULL( 'segment',segment, 'region',region, 'locale',locale, 'explain',explanation) AS detail FROM MART.CUSTOMER_SCORE_DAILY WHERE score_date BETWEEN DATEADD( 'day',-7,CURRENT_DATE()) AND CURRENT_DATE() QUALIFY ROW_NUMBER() OVER(PARTITION BY customer_id,score_date ORDER BY updated_at DESC,model_version DESC) = 1) SELECT score_date,customer_id,model_version,score,percentile,TO_JSON(detail) AS detail_json,CURRENT_TIMESTAMP() AS exported_at FROM latest WHERE score IS NOT NULL) PARTITION BY( 'score_date=' || TO_VARCHAR(score_date, 'YYYY-MM-DD')) FILE_FORMAT =(TYPE = CSV COMPRESSION = GZIP FIELD_DELIMITER = '|' RECORD_DELIMITER = '\n' FIELD_OPTIONALLY_ENCLOSED_BY = '"' NULL_IF =( '', 'NULL', '\\N')) HEADER = TRUE OVERWRITE = TRUE MAX_FILE_SIZE = 268435456 DETAILED_OUTPUT = TRUE;
